import { auth } from "@/auth";
import { redirect } from "next/navigation";
import DashboardLayout from "@/app/components/DashboardLayout";
import { getAllJobsForAdmin } from "@/app/actions/jobs";
import AdminJobActions from "@/app/components/AdminJobActions";
import Link from "next/link";

const STATUS_CONFIG: Record<string, { label: string; color: string; bg: string }> = {
    PENDING: { label: "Chờ duyệt", color: "#92400E", bg: "#FEF3C7" },
    ACTIVE: { label: "Đang hiển thị", color: "#14532D", bg: "#DCFCE7" },
    CLOSED: { label: "Đã đóng", color: "#475569", bg: "#F1F5F9" },
    REJECTED: { label: "Từ chối", color: "#991B1B", bg: "#FEE2E2" },
};

export default async function AdminJobsPage() {
    const session = await auth();
    if (!session?.user || session.user.role !== "ADMIN") redirect("/login");

    const jobs = await getAllJobsForAdmin();

    return (
        <DashboardLayout role="ADMIN" userName={session.user.name || "Admin"}>
            <div style={{ padding: "2rem" }}>
                <div style={{ marginBottom: "2rem" }}>
                    <h1 style={{ fontSize: "1.5rem", fontWeight: 800, color: "var(--text)", marginBottom: "0.25rem" }}>
                        Quản lý tất cả tin tuyển dụng
                    </h1>
                    <p style={{ color: "var(--text-muted)" }}>Hệ thống đang có {jobs.length} tin đăng.</p>
                </div>

                <div className="card" style={{ overflow: "hidden", padding: 0 }}>
                    <table style={{ width: "100%", borderCollapse: "collapse" }}>
                        <thead>
                            <tr style={{ borderBottom: "1.5px solid var(--border)", background: "var(--bg-card)" }}>
                                <th style={thStyle}>Tiêu đề</th>
                                <th style={thStyle}>Công ty</th>
                                <th style={thStyle}>Ngày đăng</th>
                                <th style={thStyle}>Trạng thái</th>
                                <th style={{ ...thStyle, textAlign: "right" }}>Thao tác</th>
                            </tr>
                        </thead>
                        <tbody>
                            {jobs.map((job) => {
                                const st = STATUS_CONFIG[job.status] || { label: job.status, color: "#64748B", bg: "#F8FAFC" };
                                return (
                                    <tr key={job.id} style={{ borderBottom: "1px solid var(--border)" }}>
                                        <td style={tdStyle}>
                                            <div style={{ fontWeight: 600, color: "var(--text)", fontSize: "0.9375rem" }}>
                                                <Link href={`/jobs/${job.slug}`} target="_blank" style={{ color: "inherit", textDecoration: "none" }}>
                                                    {job.title}
                                                </Link>
                                            </div>
                                            <div style={{ fontSize: "0.8125rem", color: "var(--text-muted)", marginTop: "0.25rem" }}>
                                                {job.location} · {job.jobType}
                                            </div>
                                        </td>
                                        <td style={{ ...tdStyle, color: "var(--text)" }}>{job.company.name}</td>
                                        <td style={{ ...tdStyle, color: "var(--text-muted)", fontSize: "0.875rem" }}>
                                            {new Date(job.createdAt).toLocaleDateString("vi-VN")}
                                        </td>
                                        <td style={tdStyle}>
                                            <span style={{ fontSize: "0.75rem", fontWeight: 700, padding: "0.375rem 0.75rem", borderRadius: "100px", background: st.bg, color: st.color }}>
                                                {st.label}
                                            </span>
                                        </td>
                                        <td style={{ ...tdStyle, textAlign: "right" }}>
                                            <AdminJobActions jobId={job.id} currentStatus={job.status} />
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>
        </DashboardLayout>
    );
}

const thStyle: React.CSSProperties = { padding: "1rem 1.25rem", textAlign: "left", fontSize: "0.8125rem", fontWeight: 700, color: "var(--text-muted)", textTransform: "uppercase" };
const tdStyle: React.CSSProperties = { padding: "1.25rem", verticalAlign: "middle" };
